-- Migração incremental: Gestão de Cotação e Expedição de Fretes
USE studiomuda;
CREATE TABLE IF NOT EXISTS transportadora (id INT AUTO_INCREMENT PRIMARY KEY,nome VARCHAR(120) NOT NULL,ativo BOOLEAN NOT NULL DEFAULT TRUE,prazo_medio_dias INT NOT NULL DEFAULT 5,observacoes VARCHAR(255));
CREATE TABLE IF NOT EXISTS tabela_contingencia (id INT AUTO_INCREMENT PRIMARY KEY,transportadora_id INT NULL,cep_inicio CHAR(8) NOT NULL,cep_fim CHAR(8) NOT NULL,peso_minimo DECIMAL(10,3) NOT NULL,peso_maximo DECIMAL(10,3) NOT NULL,valor_frete DECIMAL(12,2) NOT NULL,ativo BOOLEAN NOT NULL DEFAULT TRUE,INDEX idx_contingencia_faixa (cep_inicio,cep_fim,peso_minimo,peso_maximo),FOREIGN KEY (transportadora_id) REFERENCES transportadora(id));
CREATE TABLE IF NOT EXISTS log_cotacao (id INT AUTO_INCREMENT PRIMARY KEY,usuario_id INT NOT NULL,cliente_id INT NULL,pedido_id INT NULL,cep_destino CHAR(8) NOT NULL,peso DECIMAL(10,3) NOT NULL,comprimento DECIMAL(10,2) NOT NULL,largura DECIMAL(10,2) NOT NULL,altura DECIMAL(10,2) NOT NULL,hash_parametros CHAR(64) NOT NULL,valor_cotado DECIMAL(12,2) NOT NULL,origem_resultado VARCHAR(20) NOT NULL,transportadora_id INT NULL,data_cotacao DATETIME NOT NULL,INDEX idx_log_cotacao_hash_data (hash_parametros,data_cotacao),INDEX idx_log_cotacao_usuario_data (usuario_id,data_cotacao),FOREIGN KEY (usuario_id) REFERENCES usuario_acesso(id),FOREIGN KEY (cliente_id) REFERENCES cliente(id),FOREIGN KEY (pedido_id) REFERENCES pedido(id),FOREIGN KEY (transportadora_id) REFERENCES transportadora(id));
CREATE TABLE IF NOT EXISTS ordem_despacho (id INT AUTO_INCREMENT PRIMARY KEY,pedido_id INT NOT NULL,transportadora_id INT NOT NULL,log_cotacao_id INT NOT NULL,valor_frete DECIMAL(12,2) NOT NULL,status VARCHAR(20) NOT NULL DEFAULT 'PENDENTE',codigo_rastreio VARCHAR(80),data_despacho DATETIME,data_entrega_prevista DATETIME,data_entrega_realizada DATETIME,UNIQUE KEY uk_ordem_despacho_pedido (pedido_id),FOREIGN KEY (pedido_id) REFERENCES pedido(id),FOREIGN KEY (transportadora_id) REFERENCES transportadora(id),FOREIGN KEY (log_cotacao_id) REFERENCES log_cotacao(id));
